const raw=$input.first().json.content[0].text;
let plan;
try{plan=JSON.parse(raw.replace(/```json|```/g,'').trim());}catch(e){throw new Error('Brain parse fail: '+e.message);}
const prev=$('🧠 Prepare Mission').first().json;
plan.mission_id=prev.mission_id;
plan.operator=prev.operator;
plan.org_domain=prev.org_domain;
plan.timestamp=prev.timestamp;
plan.raw_input=prev.raw_input;
plan.version='ELITE-2.0';
return [{json:plan}];

const body=$input.first().json.body||$input.first().json;
const md=body.mission_data?JSON.parse(body.mission_data):body;
return [{json:{intel_run_id:'INTEL-'+Date.now(),timestamp:new Date().toISOString(),org_domain:md.org_domain||'YOUR_COMPANY.com',mission_id:md.mission_id||'SCHEDULED',trigger:md.trigger||'SCHEDULED',targets:md.extracted_targets||md.targets||[md.org_domain||'YOUR_COMPANY.com'],findings:[],critical_findings:[]}}];

const init=$('🟡 Init Intel Run').first().json;
const findings=[];
const criticalFindings=[];

try{const hibp=$('💀 HIBP Breach Check').first().json;
if(Array.isArray(hibp)&&hibp.length>0){const f={source:'HaveIBeenPwned',type:'DATA_BREACH',severity:'HIGH',risk_score:75,title:`${hibp.length} data breaches — ${init.org_domain}`,detail:hibp.map(b=>b.Name).join(', '),asset:init.org_domain,mitre:'T1589',action:'Force password resets for all affected accounts',timestamp:init.timestamp};
findings.push(f);if(hibp.length>2)criticalFindings.push(f);}}catch(e){}

try{const shodan=$('🔍 Shodan Exposed Services').first().json;
if(shodan.total>0&&shodan.matches){shodan.matches.slice(0,10).forEach(m=>{const risky=[22,3389,5900,23,21,445,3306,5432,27017,6379].includes(m.port);
const f={source:'Shodan',type:'EXPOSED_SERVICE',severity:risky?'HIGH':'MEDIUM',risk_score:risky?72:42,title:`Port ${m.port} exposed on ${m.ip_str}`,detail:`${m.product||'unknown'} ${m.version||''}`.trim(),asset:m.ip_str,port:m.port,mitre:'T1046',action:risky?'Restrict with firewall immediately':'Review if public access needed',timestamp:init.timestamp};
findings.push(f);if(risky)criticalFindings.push(f);});}}catch(e){}

try{const gh=$('🐙 GitHub Leak Scan').first().json;
if(gh.total_count>0){const f={source:'GitHub',type:'CREDENTIAL_EXPOSURE',severity:'CRITICAL',risk_score:95,title:`${gh.total_count} credential exposures on GitHub`,detail:gh.items?.slice(0,3).map(i=>i.html_url).join(' | ')||'',asset:'GitHub Public',mitre:'T1552.001',action:'IMMEDIATE: Review URLs, rotate credentials, remove files',timestamp:init.timestamp};
findings.push(f);criticalFindings.push(f);}}catch(e){}

try{const gs=$('🐙 GitHub Secret Scan').first().json;
if(gs.total_count>0){const f={source:'GitHub',type:'SECRET_EXPOSURE',severity:'CRITICAL',risk_score:98,title:`${gs.total_count} secrets/API keys exposed on GitHub`,detail:gs.items?.slice(0,3).map(i=>i.html_url).join(' | ')||'',asset:'GitHub Public',mitre:'T1552.001',action:'IMMEDIATE: Rotate ALL secrets. Audit full git history.',timestamp:init.timestamp};
findings.push(f);criticalFindings.push(f);}}catch(e){}

try{const nvd=$('🛡️ NVD Critical CVEs').first().json;
if(nvd.vulnerabilities&&nvd.vulnerabilities.length>0){nvd.vulnerabilities.slice(0,5).forEach(v=>{const cve=v.cve;
const cvss=cve.metrics?.cvssMetricV31?.[0]?.cvssData?.baseScore||cve.metrics?.cvssMetricV30?.[0]?.cvssData?.baseScore||0;
const f={source:'NVD',type:'CVE_CRITICAL',severity:cvss>=9?'CRITICAL':'HIGH',risk_score:Math.round(cvss*10),cve_id:cve.id,cvss_score:cvss,title:`${cve.id} (CVSS ${cvss})`,detail:(cve.descriptions?.find(d=>d.lang==='en')?.value||'').substring(0,150),mitre:'T1190',action:'Verify if applicable to your stack and patch immediately',timestamp:init.timestamp};
findings.push(f);if(cvss>=9)criticalFindings.push(f);});}}catch(e){}

try{const certs=$('🔏 SSL Cert Transparency').first().json;
if(Array.isArray(certs)){const domains=[...new Set(certs.map(c=>c.name_value).flat())].filter(d=>d&&!d.startsWith('*')&&d.includes(init.org_domain)).slice(0,25);
if(domains.length>0){findings.push({source:'CertTransparency',type:'ASSET_DISCOVERY',severity:'INFO',risk_score:20,title:`${domains.length} subdomains via cert transparency`,detail:domains.join(', '),discovered_subdomains:domains,asset:init.org_domain,mitre:'T1590',action:'Fingerprint all new subdomains',timestamp:init.timestamp});}}}catch(e){}

try{const dmarc=$('📧 DMARC Policy Check').first().json;
const hasDmarc=dmarc.Answer&&dmarc.Answer.some(a=>a.data&&a.data.includes('v=DMARC1'));
const dmarcRecord=dmarc.Answer?.find(a=>a.data?.includes('v=DMARC1'))?.data||'';
const isReject=dmarcRecord.includes('p=reject');
if(!hasDmarc||!isReject){const f={source:'DNS_Analysis',type:'EMAIL_SECURITY',severity:!hasDmarc?'HIGH':'MEDIUM',risk_score:!hasDmarc?68:45,title:!hasDmarc?'No DMARC record — domain spoofing possible':'DMARC not enforced (not p=reject)',detail:`Current: ${dmarcRecord||'NONE'}`,asset:init.org_domain,mitre:'T1566',action:!hasDmarc?'Add DMARC record with p=reject immediately':'Update DMARC to p=reject',timestamp:init.timestamp};
findings.push(f);if(!hasDmarc)criticalFindings.push(f);}}catch(e){}

try{const txt=$('🔐 DNS TXT (SPF/DMARC/DKIM)').first().json;
const hasSPF=txt.Answer&&txt.Answer.some(a=>a.data&&a.data.includes('v=spf1'));
if(!hasSPF){const f={source:'DNS_Analysis',type:'EMAIL_SECURITY',severity:'HIGH',risk_score:70,title:'No SPF record — email spoofing risk',detail:'Anyone can send email pretending to be from your domain',asset:init.org_domain,mitre:'T1566',action:'Add SPF record: v=spf1 include:yourmailprovider.com ~all',timestamp:init.timestamp};
findings.push(f);criticalFindings.push(f);}}catch(e){}

try{const ssl=$('🔒 SSL Labs Grade Check').first().json;
if(ssl.endpoints&&ssl.endpoints.length>0){ssl.endpoints.forEach(ep=>{const grade=ep.grade;
if(grade&&!['A','A+'].includes(grade)){const f={source:'SSLLabs',type:'SSL_WEAKNESS',severity:['C','D','E','F','T'].includes(grade)?'HIGH':'MEDIUM',risk_score:grade==='F'?85:grade==='C'?55:42,title:`SSL/TLS Grade ${grade} on ${ep.ipAddress}`,detail:`Grade: ${grade} | Issues: ${ep.statusMessage||'Weak cipher or config'}`,asset:ep.ipAddress,mitre:'T1573',action:`Upgrade TLS config to achieve A+ grade. Disable weak ciphers.`,timestamp:init.timestamp};
findings.push(f);if(['F','T'].includes(grade))criticalFindings.push(f);}});}}catch(e){}

const overallRisk=findings.length>0?Math.min(100,Math.round(findings.reduce((s,f)=>s+f.risk_score,0)/findings.length)):0;
const riskLevel=overallRisk>=80?'CRITICAL':overallRisk>=60?'HIGH':overallRisk>=40?'MEDIUM':'LOW';

return [{json:{...init,findings,critical_findings:criticalFindings,total_findings:findings.length,critical_count:criticalFindings.length,overall_risk_score:overallRisk,risk_level:riskLevel,completed_at:new Date().toISOString()}}];

