const init=$('🔴 Init Attack Run').first().json;
const vulns=[];
const confirmed=[];

try{const sh=$('🔍 Shodan Host Recon').first().json;
if(sh.matches){sh.matches.slice(0,8).forEach(m=>{if(m.vulns){Object.keys(m.vulns).forEach(cve=>{const f={source:'Shodan',type:'CVE_CONFIRMED',severity:'CRITICAL',risk_score:88,cve_id:cve,asset:m.ip_str,title:`CONFIRMED: ${cve} on ${m.ip_str}`,detail:`Product: ${m.product||'unknown'} | Port: ${m.port}`,mitre:'T1190',action:'Patch immediately — CVE confirmed by Shodan scanner',timestamp:init.timestamp};
vulns.push(f);confirmed.push(f);});}if(m.port){const risky=[23,5900,27017,6379,11211,50000].includes(m.port);
if(risky)confirmed.push({source:'Shodan',type:'CRITICAL_PORT',severity:'CRITICAL',risk_score:90,asset:m.ip_str,port:m.port,title:`CRITICAL port ${m.port} publicly exposed`,mitre:'T1046',action:'Block immediately via firewall',timestamp:init.timestamp});}}}}catch(e){}

try{const vt=$('🦠 VirusTotal Domain').first().json;
if(vt.data?.attributes){const mal=vt.data.attributes.last_analysis_stats?.malicious||0;
if(mal>0){const f={source:'VirusTotal',type:'MALICIOUS_CLASSIFICATION',severity:'CRITICAL',risk_score:92,asset:init.org_domain,title:`Domain flagged MALICIOUS by ${mal} vendors`,detail:`Suspicious: ${vt.data.attributes.last_analysis_stats?.suspicious||0}`,mitre:'T1583',action:'IMMEDIATE: Domain may be compromised/hijacked'};
vulns.push(f);confirmed.push(f);}}}catch(e){}

try{const hdrs=$('📋 HTTP Headers Analysis').first().json;
const headerText=typeof hdrs==='string'?hdrs:JSON.stringify(hdrs);
const missingHeaders=[];
if(!headerText.includes('Strict-Transport-Security'))missingHeaders.push('HSTS missing');
if(!headerText.includes('Content-Security-Policy'))missingHeaders.push('CSP missing');
if(!headerText.includes('X-Frame-Options'))missingHeaders.push('X-Frame-Options missing — clickjacking possible');
if(!headerText.includes('X-Content-Type-Options'))missingHeaders.push('X-Content-Type-Options missing');
if(missingHeaders.length>0){vulns.push({source:'HeaderAnalysis',type:'MISSING_SECURITY_HEADERS',severity:'MEDIUM',risk_score:45,asset:init.org_domain,title:`${missingHeaders.length} security headers missing`,detail:missingHeaders.join(' | '),mitre:'T1189',action:'Add missing security headers to web server config',timestamp:init.timestamp});}}catch(e){}

try{const ww=$('🌐 WhatWeb Fingerprint').first().json;
const wwText=typeof ww==='string'?ww:JSON.stringify(ww);
if(wwText){vulns.push({source:'WhatWeb',type:'TECHNOLOGY_FINGERPRINT',severity:'INFO',risk_score:15,asset:init.org_domain,title:'Technology stack fingerprinted',detail:wwText.substring(0,300),mitre:'T1592',action:'Review if technology disclosure is acceptable',timestamp:init.timestamp});}}catch(e){}

try{const nmap=$('🎯 HackerTarget Nmap').first().json;
const nmapText=typeof nmap==='string'?nmap:JSON.stringify(nmap);
if(nmapText&&nmapText.includes('open')){const openPorts=nmapText.match(/\d+\/tcp\s+open/g)||[];
if(openPorts.length>0){vulns.push({source:'Nmap',type:'PORT_SCAN',severity:'INFO',risk_score:20,asset:init.targets[0],title:`${openPorts.length} open ports discovered`,detail:openPorts.join(', ').substring(0,200),mitre:'T1046',action:'Review all open ports — close unnecessary services',timestamp:init.timestamp});}}catch(e){}

const criticalVulns=[...vulns,...confirmed].filter(v=>['CRITICAL','HIGH'].includes(v.severity));
return [{json:{...init,scan_results:{vulnerabilities:vulns,confirmed_exploits:confirmed,total_vulnerabilities:vulns.length,confirmed_count:confirmed.length,critical_vulns:criticalVulns},phase:'ANALYZING'}}];

