const alert=$('🔵 Init Defend Run').first().json;
const en={};

try{const ab=$('🛡️ AbuseIPDB Check').first().json;
if(ab.data){en.abuseipdb={abuse_score:ab.data.abuseConfidenceScore,country:ab.data.countryCode,isp:ab.data.isp,usage_type:ab.data.usageType,total_reports:ab.data.totalReports,is_tor:ab.data.isTor};}}catch(e){}

try{const vt=$('🦠 VirusTotal IP').first().json;
if(vt.data?.attributes){en.virustotal={malicious:vt.data.attributes.last_analysis_stats?.malicious||0,suspicious:vt.data.attributes.last_analysis_stats?.suspicious||0,reputation:vt.data.attributes.reputation,as_owner:vt.data.attributes.as_owner};}}catch(e){}

try{const geo=$('🌍 IP Geolocation').first().json;
en.geolocation={city:geo.city,region:geo.region,country:geo.country_name,country_code:geo.country_code,org:geo.org,timezone:geo.timezone};}catch(e){}

try{const otx=$('👽 OTX IP Intel').first().json;
if(otx.pulse_info){en.otx={pulse_count:otx.pulse_info.count,reputation:otx.reputation};}}catch(e){}

try{const sh=$('🔍 Shodan IP Context').first().json;
if(sh.ports){en.shodan={ports:sh.ports,org:sh.org,isp:sh.isp,is_scanner:(sh.tags||[]).includes('scanner'),os:sh.os,country:sh.country_name};}}catch(e){}

try{const tf=$('🦊 ThreatFox IOC Check').first().json;
if(tf.data&&tf.data.length>0){en.threatfox={malware_family:tf.data[0].malware_printable,threat_type:tf.data[0].threat_type,confidence:tf.data[0].confidence_level};}}catch(e){}

try{const feodo=$('💀 Feodo C2 Blocklist').first().json;
if(Array.isArray(feodo)){const match=feodo.find(e=>e.ip_address===alert.source_ip);
if(match){en.feodo={is_c2:true,malware:match.malware,status:match.status,first_seen:match.first_seen};}}}catch(e){}

const score=Math.min(100,
  (en.abuseipdb?.abuse_score||0)+
  (en.virustotal?.malicious||0)*5+
  (en.otx?.pulse_count||0)>0?20:0+
  (en.abuseipdb?.is_tor?30:0)+
  (en.threatfox?.malware_family?40:0)+
  (en.feodo?.is_c2?50:0));

const level=score>=80?'CRITICAL':score>=60?'HIGH':score>=30?'MEDIUM':'LOW';

return [{json:{...alert,enrichment:en,composite_threat_score:score,threat_level:level,is_known_malicious:score>=60,is_c2_server:!!en.feodo?.is_c2,is_known_malware:!!en.threatfox?.malware_family,phase:'TRIAGING'}}];

