try{report=JSON.parse(raw.replace(/```json|```/g,'').trim());}catch(e){report={overall_compliance_score:0,frameworks:{},critical_gaps:[],audit_readiness:'NOT_READY',compliance_summary:'Analysis error',slack_message:'📋 Compliance scan complete'};}
