// AEGIS ELITE — Session Validator
// Validates webhook secret + timestamp freshness
// Prevents replay attacks and unauthorized triggers
const headers = $json.headers || {};
const body    = $json.body    || $json;

// Webhook secret check (set AEGIS_WEBHOOK_SECRET in n8n env vars)
const provided = headers['x-aegis-secret'] || headers['authorization'] || '';
const expected = $env.AEGIS_WEBHOOK_SECRET || 'CHANGE_ME_IN_ENV_VARS';
if (provided && provided !== expected && provided !== `Bearer ${expected}`) {
    throw new Error('AUTH_FAILED: Invalid webhook secret');
}

// Timestamp freshness (prevent replay attacks - 5 min window)
const reqTs   = parseInt(headers['x-aegis-timestamp'] || Date.now());
const ageSecs = (Date.now() - reqTs) / 1000;
if (ageSecs > 300) throw new Error(`REPLAY_ATTACK: Request ${Math.round(ageSecs)}s old`);

return {
    ...body,
    session_validated_at: new Date().toISOString(),
    org_domain: body.domain || body.org_domain || 'YOUR_COMPANY.com',
    operator:   body.operator || body.user_id || 'webhook',
    user_tier:  body.tier || 'pro',
};

// AEGIS ELITE — Input Sanitizer
// Strips prompt injections, jailbreaks, oversized payloads
// Runs BEFORE the AI sees ANY user input
const raw = $json.body?.mission || $json.mission || $json.raw_input || $json.message || '';

const INJECTIONS = [
    { re: /<\/?(system|prompt|instruction|context)[^>]*>/gi, label:'XML_TAG' },
    { re: /ignore\s+(all\s+)?(previous|prior|above)\s+instructions?/gi, label:'INSTRUCTION_OVERRIDE' },
    { re: /you\s+are\s+now\s+(a\s+)?(new|different|unrestricted)/gi, label:'ROLE_HIJACK' },
    { re: /maintenance\s*mode|debug\s*mode|developer\s*mode/gi, label:'MODE_SWITCH' },
    { re: /\bDAN\b|do\s+anything\s+now/gi, label:'DAN_JAILBREAK' },
    { re: /override\s+(scope|auth|verification|security)/gi, label:'SECURITY_OVERRIDE' },
    { re: /scan\s+(google|microsoft|amazon|facebook|government|military)/gi, label:'FORBIDDEN_TARGET' },
    { re: /(?:execute|eval|exec)\s*\([^)]*\)/gi, label:'CODE_INJECTION' },
    { re: /\.\.[\/\\]|\/etc\/passwd|\/proc\//gi, label:'PATH_TRAVERSAL' },
    { re: /(?:password|passwd|pwd)\s*[:=]\s*\S+/gi, label:'CREDENTIAL_LEAK' },
];

let sanitized = raw;
const detected = [];
for (const {re, label} of INJECTIONS) {
    if (re.test(sanitized)) { detected.push(label); sanitized = sanitized.replace(re,'[REDACTED]'); }
}
sanitized = sanitized.replace(/<[^>]+>/g,'').substring(0, 2000).trim();

if (detected.length) console.log(`🚨 INJECTION BLOCKED: ${detected.join(',')} | Input: "${raw.substr(0,80)}"`);

return {
    ...$json,
    raw_input: sanitized,
    original_input: raw,
    injection_flags: detected,
    injection_blocked: detected.length > 0,
    sanitized_at: new Date().toISOString(),
};

// AEGIS ELITE — Rate Limit Check
// Enforces per-tier scan limits
const tier = $json.user_tier || 'pro';
const mode = ($json.selected_mode || 'INTEL').toUpperCase();
const LIMITS = {
    free:       { daily:1,   attack:false },
    starter:    { daily:5,   attack:false },
    pro:        { daily:10,  attack:true  },
    business:   { daily:50,  attack:true  },
    enterprise: { daily:999, attack:true  },
};
const L = LIMITS[tier] || LIMITS.free;
if (!L.attack && (mode==='ATTACK'||mode==='AUTO')) {
    throw new Error(`RATE_LIMIT: Attack mode requires Pro+ tier. Current: ${tier}`);
}
return { ...$json, rate_limit_tier:tier, rate_limit_passed:true, rate_checked_at:new Date().toISOString() };

// AEGIS ELITE — Scope Enforcer
// THE critical security gate. Runs AFTER AI.
// AI CANNOT override this. Ever.
// Blocks SSRF, out-of-scope targets, private IPs.
const verified = $json.org_domain || 'YOUR_COMPANY.com';
const targets  = $json.extracted_targets || [verified];
const norm     = d => (d||'').toLowerCase().replace(/^https?:\/\//,'').replace(/\/.*/,'').replace(/^www\./,'').trim();
const normV    = norm(verified);

const SSRF_BLOCKS = [
    /^10\./, /^172\.(1[6-9]|2\d|3[01])\./, /^192\.168\./, /^127\./,
    /^169\.254\./, /^0\./, /^::1$/, /localhost/i, /metadata\.google\.internal/i,
    /169\.254\.169\.254/,   // AWS metadata
];

const violations=[], allowed=[];
for (const t of targets) {
    const nt = norm(t);
    if (SSRF_BLOCKS.some(r=>r.test(nt))) { violations.push({target:t,reason:'SSRF_BLOCKED'}); continue; }
    if (nt===normV || nt.endsWith('.'+normV)) { allowed.push(t); }
    else { violations.push({target:t, reason:'OUT_OF_SCOPE'}); }
}

if (violations.length) console.log(`🚨 SCOPE VIOLATION: ${JSON.stringify(violations)}`);
if (allowed.length===0) throw new Error(`SCOPE_BLOCK: All targets out of scope or SSRF blocked: ${violations.map(v=>v.target).join(',')}`);

return {
    ...$json,
    extracted_targets: allowed,
    scope_violations: violations,
    scope_status: violations.length===0 ? 'CLEAN':'VIOLATIONS_REMOVED',
    scope_enforced_at: new Date().toISOString(),
};

// AEGIS ELITE — Anomaly Detector
// Runs on every SIEM alert BEFORE enrichment.
// Boosts risk score for known attack patterns.
const a = $json; const ip = a.source_ip||''; let score = parseInt(a.composite_threat_score)||50;
const anomalies = [];

const addA = (type,sev,boost,detail) => { anomalies.push({type,severity:sev,score_boost:boost,detail}); score=Math.min(100,score+boost); };

if (a.is_tor_exit===true||/^185\.220\.|^199\.87\.154/.test(ip)) addA('TOR_EXIT_NODE','CRITICAL',35,'Source is Tor exit node — anonymized malicious activity');
if (['185.220.','45.142.','91.108.','94.102.'].some(r=>ip.startsWith(r)))  addA('KNOWN_BAD_RANGE','HIGH',25,`IP ${ip} in high-malicious-activity range`);
const h=new Date().getUTCHours(); if(h>=1&&h<=5) addA('OFF_HOURS','MEDIUM',15,`Alert at ${h}:00 UTC — common automated attack window`);
if((parseInt(a.previous_alert_count)||0)>=20) addA('ALERT_FLOOD','HIGH',20,`${a.previous_alert_count} previous alerts — likely automated`);
if(/lateral|pivot|mimikatz|psexec|pass.the.hash/i.test(a.alert_description||'')) addA('LATERAL_MOVEMENT','CRITICAL',30,'Lateral movement indicators in alert');
if(a.is_apt_campaign===true)  addA('APT_CAMPAIGN','CRITICAL',40,'Linked to known APT campaign');
if(a.is_c2_server===true)     addA('C2_SERVER','CRITICAL',45,'Confirmed C2 server');
if((a.alert_types||[]).length>=3) addA('MULTI_VECTOR','HIGH',25,`${(a.alert_types||[]).length} simultaneous attack vectors`);

return {...a, anomalies_detected:anomalies, anomaly_count:anomalies.length, composite_threat_score:score, anomaly_checked_at:new Date().toISOString()};

// AEGIS ELITE — HIGH Alert Handler
// Handles HIGH severity (not CRITICAL).
// No auto-block, no on-call page, no Telegram panic.
