const emailDomain=(req.user_email||'').split('@')[1]||'';
const claimedDomain=(req.domain||'').replace(/^www\./,'');
if(emailDomain&&emailDomain===claimedDomain){score+=30;f.push('+30 Corporate email matches domain');}
else if(emailDomain){score-=40;f.push('-40 Personal/unrelated email (HIGH RISK)');}

const age=parseInt(req.account_age_days)||0;
if(age>90){score+=20;f.push('+20 Account >90 days');}
else if(age>30){score+=10;f.push('+10 Account >30 days');}
else if(age<1){score-=25;f.push('-25 Account created today (SUSPICIOUS)');}

const pt=req.payment_type||'';
if(pt==='corporate_card'){score+=25;f.push('+25 Corporate card');}
else if(pt==='credit_card'){score+=15;f.push('+15 Personal card');}
else if(pt==='prepaid'){score-=35;f.push('-35 Prepaid card');}
else if(pt==='crypto'){score-=40;f.push('-40 Crypto payment');}

if(req.is_tor){score-=50;f.push('-50 Tor detected');}
if(req.is_vpn){score-=20;f.push('-20 VPN detected');}

const utcH=new Date().getUTCHours();
if(utcH>=8&&utcH<=18){score+=10;f.push('+10 Business hours');}else{score-=10;f.push('-10 Off-hours');}

const fails=parseInt(req.previous_failed_verifications)||0;
if(fails>3){score-=20;f.push(`-20 ${fails} previous failures`);}

score=Math.max(0,Math.min(100,score));
let action=score>=70?'AUTO_APPROVE':score>=50?'PROCEED':score>=30?'MANUAL_REVIEW':'REJECT';

const chars='0123456789abcdef';
const token='aegis-verify='+Array.from({length:32},()=>chars[Math.floor(Math.random()*16)]).join('');

return {...req, trust_score:score, trust_action:action, trust_factors:f,
    requires_manual_review:action==='MANUAL_REVIEW',
    verification_token:token, trust_evaluated_at:new Date().toISOString()};

