// AEGIS ELITE — Data Loss Prevention Monitor
// Scans outgoing reports for credentials, PII, secrets.
// Redacts before delivery. Logs violations for compliance.
const content = JSON.stringify($json).toLowerCase(); const flags=[];

const patterns=[
    {re:/(?:password|passwd)\s*[:=]\s*\S+/gi,      label:'PLAINTEXT_PASSWORD'},
    {re:/(?:api[_-]?key)\s*[:=]\s*[a-z0-9_\-]{10,}/gi, label:'API_KEY'},
    {re:/(?:aws_access|aws_secret)\s*[:=]\s*\S+/gi,label:'AWS_CRED'},
    {re:/ghp_[a-zA-Z0-9]{36}/g,                   label:'GITHUB_TOKEN'},
    {re:/sk-[a-zA-Z0-9]{40,}/g,                   label:'AI_API_KEY'},
    {re:/xox[baprs]-[0-9A-Za-z\-]+/g,             label:'SLACK_TOKEN'},
    {re:/\b\d{3}-\d{2}-\d{4}\b/g,                 label:'SSN_PII'},
    {re:/\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14})\b/g, label:'CREDIT_CARD_PII'},
];

for(const {re,label} of patterns){
    if(re.test(content)) flags.push({type:label,severity:flags.length===0?'CRITICAL':'HIGH',action:'REDACTED'});
}

if(flags.length) console.log(`🚨 DLP ALERT: ${flags.map(f=>f.type).join(',')}`);

return {...$json, dlp_flags:flags, dlp_violations:flags.length,
    dlp_status:flags.length===0?'CLEAN':'FLAGS_DETECTED', dlp_checked_at:new Date().toISOString()};

